//             description: news.description,
//             date: news.datePublished.slice(0, 10),
//           })))));
//     }

//     //return result;
// }, [category]);

  // console.log(categoryNews);

  return (
    <div className="HomePage">
      <button
        className="hom"
        type="button"
        onClick={(e) => {
          e.preventDefault();
          setCategory('sports');
          console.log(category);
        }}
      >
        Click
      </button>
      <button
        className="hom"
        type="button"
        onClick={(e) => {
          e.preventDefault();
          setCategory('');
          console.log(category);
        }}
